import json
from rabbitmq_client import MessageBroker

class OrderService:
    def __init__(self):
        self.broker = MessageBroker()

    def create_order(self, order_data):
        # Save order to local database
        order_id = self.save_order(order_data)

        # Publish OrderCreated event
        event = {
            'eventType': 'OrderCreated',
            'orderId': order_id,
            'customerId': order_data['customerId'],
            'items': order_data['items'],
            'totalAmount': order_data['totalAmount'],
            'timestamp': datetime.utcnow().isoformat()
        }

        self.broker.publish('orders.exchange', event, routing_key='order.created')
        return order_id

# Inventory Service - Consuming OrderCreated event
class InventoryService:
    def __init__(self):
        self.broker = MessageBroker()
        self.broker.subscribe('orders.exchange', self.handle_order_created, 'order.created')

    def handle_order_created(self, event):
        try:
            # Reserve inventory items
            for item in event['items']:
                if not self.reserve_item(item['productId'], item['quantity']):
                    # Publish InventoryFailed event if reservation fails
                    self.publish_inventory_failed(event['orderId'], item['productId'])
                    return

            # Publish InventoryReserved event on success
            self.publish_inventory_reserved(event['orderId'])

        except Exception as e:
            # Will retry automatically, then go to DLQ if still failing
            raise Exception(f"Failed to reserve inventory: {str(e)}")

# Payment Service - Saga coordination example
class PaymentService:
    def __init__(self):
        self.broker = MessageBroker()
        self.broker.subscribe('orders.exchange', self.handle_payment_request, 'payment.request')

    def handle_payment_request(self, event):
        try:
            payment_success = self.process_payment(
                event['orderId'], 
                event['totalAmount'],
                event['paymentMethod']
            )

            if payment_success:
                self.publish_payment_success(event['orderId'])
            else:
                self.publish_payment_failed(event['orderId'])

        except Exception as e:
            raise Exception(f"Payment processing failed: {str(e)}")

    def publish_payment_failed(self, order_id):
        # Compensating transaction - triggers inventory rollback
        event = {
            'eventType': 'PaymentFailed',
            'orderId': order_id,
            'timestamp': datetime.utcnow().isoformat()
        }
        self.broker.publish('orders.exchange', event, routing_key='payment.failed')
